#include <bits/stdc++.h>
using namespace std;
const int N=1003;
struct Node{
	int l,r,h,id;
}p[N];
bool cmp(Node x,Node y){
	return x.h>y.h;
}
int n,s,t,ans=1e9,f[N][2];
int main(){
	scanf("%d%d%d",&n,&s,&t);
	for(int i=1;i<=n;i++){
		scanf("%d%d%d",&p[i].l,&p[i].r,&p[i].h);
		p[i].id=i;
	}
	if(s==t){
		printf("0");
		return 0;
	}
	sort(p+1,p+n+1,cmp);
	for(int i=1;i<=n;i++)
		if(p[i].id==s){
			s=i;
			break;
		}
	for(int i=1;i<=n;i++)
		if(p[i].id==t){
			t=i;
			break;
		}
	memset(f,63,sizeof(f));
	f[s][0]=0,f[s][1]=p[s].r-p[s].l;
	for(int i=s;i<t;i++){
		if(f[i][0]>1e9)
			continue;
		int nxt1=0,nxt2=0;
		for(int j=i+1;j<=t && (!nxt1 || !nxt2);j++){
			if(!nxt1 && p[j].l<=p[i].l && p[i].l<=p[j].r)
				nxt1=j;
			if(!nxt2 && p[j].l<=p[i].r && p[i].r<=p[j].r)
				nxt2=j;
		}
		if(nxt1){
			f[nxt1][0]=min(f[nxt1][0],f[i][0]+p[i].h-p[nxt1].h+p[i].l-p[nxt1].l);
			f[nxt1][1]=min(f[nxt1][1],f[i][0]+p[i].h-p[nxt1].h+p[nxt1].r-p[i].l);
			if(nxt1==t)
				ans=min(ans,f[i][0]+p[i].h-p[nxt1].h);
		}
		if(nxt2){
			f[nxt2][0]=min(f[nxt2][0],f[i][1]+p[i].h-p[nxt2].h+p[i].r-p[nxt2].l);
			f[nxt2][1]=min(f[nxt2][1],f[i][1]+p[i].h-p[nxt2].h+p[nxt2].r-p[i].r);
			if(nxt2==t)
				ans=min(ans,f[i][1]+p[i].h-p[nxt2].h);
		}
	}
	if(f[t][0]>1e9)
		printf("-1");
	else
		printf("%d",ans);
	return 0;
}
